evaluators.evaluation_logic:
const checkpoints = [];

const services = JSON.parse(localStorage.getItem('services') || '[]');
const timelines = JSON.parse(localStorage.getItem('service_timeline_options') || '[]');
const quotes = JSON.parse(localStorage.getItem('service_quote_requests') || '[]');

// Identify mid-rise office services that can handle 3 floors
const candidateServices = services.filter(s => (
  s.category === 'commercial_buildings' &&
  typeof s.min_floors === 'number' &&
  typeof s.max_floors === 'number' &&
  s.min_floors <= 3 &&
  s.max_floors >= 3
));

function locationLooksLikeDenverCO(loc) {
  if (!loc || typeof loc !== 'string') return false;
  const lower = loc.toLowerCase();
  return lower.includes('denver') && (lower.includes('co') || lower.includes('colorado'));
}

// Quotes that match the project basics: correct service type, budget, floors, and location
const qualifyingQuotesBase = quotes.filter(q => {
  const svc = candidateServices.find(s => s.id === q.serviceId);
  if (!svc) return false;
  if (Number(q.estimated_budget) !== 2000000) return false;
  if (Number(q.number_of_floors) !== 3) return false;
  if (!locationLooksLikeDenverCO(q.project_location)) return false;
  return true;
});

// CP1 (0.50): User submitted at least one quote with correct service, floors, budget, and Denver, CO location
checkpoints.push({
  passed: qualifyingQuotesBase.length > 0,
  weight: 0.5
});

// Determine shortest available timeline option for that service with max_months <= 12
let shortestTimelineId = null;
if (candidateServices.length > 0) {
  const svcId = candidateServices[0].id;
  const optionsWithinLimit = timelines.filter(t => (
    t.serviceId === svcId &&
    typeof t.max_months === 'number' &&
    t.max_months <= 12
  ));
  if (optionsWithinLimit.length > 0) {
    optionsWithinLimit.sort((a, b) => (a.min_months || 0) - (b.min_months || 0));
    shortestTimelineId = optionsWithinLimit[0].id;
  }
}

const quotesWithShortestTimeline = shortestTimelineId
  ? qualifyingQuotesBase.filter(q => q.timelineOptionId === shortestTimelineId)
  : [];

// CP2 (0.50): Among those quotes, user chose the shortest available timeline under 12 months
checkpoints.push({
  passed: quotesWithShortestTimeline.length > 0,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('project_case_studies') || '[]');
const lists = JSON.parse(localStorage.getItem('project_comparison_lists') || '[]');
const currentListId = localStorage.getItem('project_comparison_current_id');
const currentList = currentListId ? lists.find(l => l.id === currentListId) : null;

// Qualifying TX healthcare hospital projects with budget >= 50M and completion_year >= 2021
const qualifyingProjects = projects.filter(p => (
  p.sector === 'healthcare' &&
  p.location_state === 'TX' &&
  typeof p.budget === 'number' && p.budget >= 50000000 &&
  typeof p.completion_year === 'number' && p.completion_year >= 2021
));

// Most recent qualifying project by completion_date, then completion_year
let mostRecentProject = null;
if (qualifyingProjects.length > 0) {
  mostRecentProject = qualifyingProjects.slice().sort((a, b) => {
    const da = a.completion_date ? new Date(a.completion_date).getTime() : null;
    const db = b.completion_date ? new Date(b.completion_date).getTime() : null;
    if (da != null && db != null) return db - da;
    if (db != null) return 1;
    if (da != null) return -1;
    return (b.completion_year || 0) - (a.completion_year || 0);
  })[0];
}

const comparisonIds = currentList && Array.isArray(currentList.project_ids)
  ? currentList.project_ids
  : [];

// CP1 (0.40): User added at least one qualifying TX healthcare project (>= $50M, >= 2021) to comparison
const qualifyingInComparison = comparisonIds.filter(id => (
  qualifyingProjects.some(p => p.id === id)
));
checkpoints.push({
  passed: qualifyingInComparison.length > 0,
  weight: 0.4
});

// CP2 (0.60): User added the most recent qualifying Texas healthcare project to comparison
checkpoints.push({
  passed: mostRecentProject != null && comparisonIds.includes(mostRecentProject.id),
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const slots = JSON.parse(localStorage.getItem('branch_time_slots') || '[]');
const appts = JSON.parse(localStorage.getItem('site_visit_appointments') || '[]');

const searchPostal = '94107';

function estimateDistance(branchPostal, searchPostal) {
  const bp = typeof branchPostal === 'string' ? branchPostal : '';
  if (bp === searchPostal) return 5;
  if (bp.slice(0, 3) === searchPostal.slice(0, 3)) return 25;
  if (bp.slice(0, 2) === searchPostal.slice(0, 2)) return 75;
  return 1000;
}

function isAugust2026(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d)) return false;
  return d.getUTCFullYear() === 2026 && d.getUTCMonth() === 7; // August = 7
}

// Find nearest active branch within 50 km of 94107, using same heuristic as business logic
const activeBranches = branches.filter(b => b.is_active);
const branchesWithDistance = activeBranches.map(b => ({
  branch: b,
  distance: estimateDistance(b.postal_code, searchPostal)
}));
const within50 = branchesWithDistance.filter(x => x.distance <= 50);
let nearestBranchId = null;
if (within50.length > 0) {
  within50.sort((a, b) => a.distance - b.distance);
  nearestBranchId = within50[0].branch.id;
}

// Find earliest morning time slot before 11:00 AM in August 2026 at that branch
let earliestMorningSlot = null;
if (nearestBranchId) {
  const candidateSlots = slots.filter(s => (
    s.branchId === nearestBranchId &&
    s.is_morning_slot === true &&
    isAugust2026(s.start_datetime)
  ));
  const filteredByTime = candidateSlots.filter(s => {
    const d = new Date(s.start_datetime);
    if (isNaN(d)) return false;
    const hour = d.getUTCHours();
    return hour < 11;
  });
  if (filteredByTime.length > 0) {
    filteredByTime.sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));
    earliestMorningSlot = filteredByTime[0];
  }
}

// Appointments for warehouse/industrial projects at the nearest branch in August 2026
const apptsForNearestBranchAugWarehouse = appts.filter(a => {
  if (a.project_type !== 'warehouse_industrial') return false;
  if (!nearestBranchId || a.branchId !== nearestBranchId) return false;
  if (!a.preferred_date || !isAugust2026(a.preferred_date)) return false;
  return true;
});

// CP1 (0.40): User scheduled a warehouse/industrial site visit at the nearest active branch in August 2026
checkpoints.push({
  passed: apptsForNearestBranchAugWarehouse.length > 0,
  weight: 0.4
});

// CP2 (0.60): That appointment uses the earliest available morning (< 11:00) slot in August 2026 at that branch
let usesEarliestMorningSlot = false;
if (earliestMorningSlot && apptsForNearestBranchAugWarehouse.length > 0) {
  usesEarliestMorningSlot = apptsForNearestBranchAugWarehouse.some(a => (
    a.timeSlotId === earliestMorningSlot.id ||
    a.scheduled_start_datetime === earliestMorningSlot.start_datetime
  ));
}

checkpoints.push({
  passed: usesEarliestMorningSlot,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const items = JSON.parse(localStorage.getItem('rental_cart_items') || '[]');
const equipmentItems = JSON.parse(localStorage.getItem('equipment_items') || '[]');
const extras = JSON.parse(localStorage.getItem('rental_extras') || '[]');

let rentalSummaryViewedRaw = localStorage.getItem('task4_rentalSummaryViewed');
let rentalSummaryViewed = false;
try {
  rentalSummaryViewed = JSON.parse(rentalSummaryViewedRaw || 'false');
} catch (e) {
  rentalSummaryViewed = rentalSummaryViewedRaw === 'true';
}

function isJune1To5_2026(dateStr, isStart) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d)) return false;
  const y = d.getUTCFullYear();
  const m = d.getUTCMonth(); // June = 5
  const day = d.getUTCDate();
  if (y !== 2026 || m !== 5) return false;
  if (isStart) return day === 1;
  return day === 5;
}

// Catalog: qualifying excavators (>=18 tons, daily_rate < 700)
const qualifyingExcavatorsCatalog = equipmentItems.filter(e => (
  e.equipment_type === 'excavator' &&
  typeof e.operating_weight_tons === 'number' && e.operating_weight_tons >= 18 &&
  typeof e.daily_rate === 'number' && e.daily_rate < 700 &&
  e.is_available
));

let cheapestExcavator = null;
if (qualifyingExcavatorsCatalog.length > 0) {
  cheapestExcavator = qualifyingExcavatorsCatalog.slice().sort((a, b) => a.daily_rate - b.daily_rate)[0];
}

// Cart items: excavator matching filters and dates
const excavatorCartItems = items.filter(item => {
  const eq = equipmentItems.find(e => e.id === item.equipmentId);
  if (!eq) return false;
  if (eq.equipment_type !== 'excavator') return false;
  if (typeof eq.operating_weight_tons !== 'number' || eq.operating_weight_tons < 18) return false;
  if (typeof eq.daily_rate !== 'number' || eq.daily_rate >= 700) return false;
  if (!isJune1To5_2026(item.rental_start_date, true)) return false;
  if (!isJune1To5_2026(item.rental_end_date, false)) return false;
  if (Number(item.quantity || 0) < 1) return false;
  return true;
});

// CP1 (0.35): At least one excavator cart item meeting criteria AND using the cheapest qualifying excavator model
const excavatorItemsUsingCheapest = cheapestExcavator
  ? excavatorCartItems.filter(item => item.equipmentId === cheapestExcavator.id)
  : [];
checkpoints.push({
  passed: excavatorItemsUsingCheapest.length > 0,
  weight: 0.35
});

// Cart items: concrete mixer (capacity >= 5 cu ft, rating >= 4.0) with same dates
const mixerCartItems = items.filter(item => {
  const eq = equipmentItems.find(e => e.id === item.equipmentId);
  if (!eq) return false;
  if (eq.equipment_type !== 'concrete_mixer') return false;
  if (typeof eq.capacity_cu_ft !== 'number' || eq.capacity_cu_ft < 5) return false;
  if (typeof eq.customer_rating !== 'number' || eq.customer_rating < 4.0) return false;
  if (!isJune1To5_2026(item.rental_start_date, true)) return false;
  if (!isJune1To5_2026(item.rental_end_date, false)) return false;
  if (Number(item.quantity || 0) < 1) return false;
  return true;
});

// CP2 (0.35): At least one qualifying concrete mixer cart item for June 1–5, 2026
checkpoints.push({
  passed: mixerCartItems.length > 0,
  weight: 0.35
});

// Standard damage waiver applied to both excavator and mixer items
const standardDamageExtra = extras.find(ex => ex.code === 'standard_damage_waiver');
let damageWaiverAppliedToBoth = false;
if (standardDamageExtra && excavatorItemsUsingCheapest.length > 0 && mixerCartItems.length > 0) {
  const chosenExcavatorItem = excavatorItemsUsingCheapest[0];
  const chosenMixerItem = mixerCartItems[0];
  const allItems = [chosenExcavatorItem, chosenMixerItem];
  damageWaiverAppliedToBoth = allItems.every(item => (
    Array.isArray(item.selected_extra_ids) && item.selected_extra_ids.includes(standardDamageExtra.id)
  ));
}

// CP3 (0.20): Standard damage waiver insurance applied to both relevant cart items
checkpoints.push({
  passed: damageWaiverAppliedToBoth,
  weight: 0.2
});

// CP4 (0.10): User proceeded to the rental summary view
checkpoints.push({
  passed: !!rentalSummaryViewed,
  weight: 0.1
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('maintenance_programs') || '[]');
const requests = JSON.parse(localStorage.getItem('maintenance_quote_requests') || '[]');

// Qualifying industrial programs: emergency up_to_2_hours, monthly_fee <= 1500
const qualifyingPrograms = programs.filter(p => (
  p.is_active &&
  p.facility_type === 'industrial' &&
  p.emergency_response_time === 'up_to_2_hours' &&
  typeof p.monthly_fee === 'number' && p.monthly_fee <= 1500
));

let longestProgram = null;
if (qualifyingPrograms.length > 0) {
  longestProgram = qualifyingPrograms.slice().sort((a, b) => (
    (b.warranty_length_months || 0) - (a.warranty_length_months || 0)
  ))[0];
}

// User-created requests (id prefix from business logic)
const userRequests = requests.filter(r => (
  typeof r.id === 'string' && r.id.indexOf('maintQuote_') === 0
));

// CP1 (0.40): Quote request for a qualifying industrial fast-response plan, marked as existing facility
const qualifyingRequests = userRequests.filter(r => (
  qualifyingPrograms.some(p => p.id === r.maintenanceProgramId) &&
  r.facility_status === 'existing_facility'
));
checkpoints.push({
  passed: qualifyingRequests.length > 0,
  weight: 0.4
});

// CP2 (0.60): Quote request specifically for the longest-warranty qualifying plan
const requestedLongest = longestProgram
  ? qualifyingRequests.some(r => r.maintenanceProgramId === longestProgram.id)
  : false;

checkpoints.push({
  passed: requestedLongest,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const courses = JSON.parse(localStorage.getItem('training_courses') || '[]');
const sessions = JSON.parse(localStorage.getItem('training_sessions') || '[]');
const registrationsAll = JSON.parse(localStorage.getItem('course_registrations') || '[]');

// Only consider user-created registrations (runtime IDs)
const registrations = registrationsAll.filter(r => (
  typeof r.id === 'string' && r.id.indexOf('courseReg_') === 0
));

function isApril2026(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d)) return false;
  return d.getUTCFullYear() === 2026 && d.getUTCMonth() === 3; // April = 3
}

// Sessions that match: safety_compliance, course duration >= 2 days, start in April 2026
const matchingSessions = sessions.filter(sess => {
  if (sess.status !== 'scheduled') return false;
  if (!isApril2026(sess.start_date)) return false;
  const course = courses.find(c => c.id === sess.courseId);
  if (!course) return false;
  if (course.category !== 'safety_compliance') return false;
  if (typeof course.duration_days !== 'number' || course.duration_days < 2) return false;
  return true;
});

// Determine cheapest matching session by price per participant
let cheapestSession = null;
if (matchingSessions.length > 0) {
  cheapestSession = matchingSessions.slice().sort((a, b) => {
    const courseA = courses.find(c => c.id === a.courseId);
    const priceA = a.price_per_participant != null
      ? a.price_per_participant
      : (courseA ? courseA.base_price_per_participant : 0);
    const courseB = courses.find(c => c.id === b.courseId);
    const priceB = b.price_per_participant != null
      ? b.price_per_participant
      : (courseB ? courseB.base_price_per_participant : 0);
    return priceA - priceB;
  })[0];
}

// CP1 (0.40): User registered exactly one participant for any qualifying April 2026 safety/compliance 2+ day session
const qualifyingRegs = registrations.filter(r => {
  const sess = matchingSessions.find(s => s.id === r.sessionId && s.courseId === r.courseId);
  if (!sess) return false;
  if (Number(r.number_of_participants || 0) !== 1) return false;
  return true;
});
checkpoints.push({
  passed: qualifyingRegs.length > 0,
  weight: 0.4
});

// CP2 (0.60): User registered one participant for the cheapest qualifying session
let registeredCheapest = false;
if (cheapestSession) {
  registeredCheapest = registrations.some(r => (
    r.sessionId === cheapestSession.id &&
    r.courseId === cheapestSession.courseId &&
    Number(r.number_of_participants || 0) === 1
  ));
}

checkpoints.push({
  passed: registeredCheapest,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const estimates = JSON.parse(localStorage.getItem('cost_estimates') || '[]');
const requests = JSON.parse(localStorage.getItem('estimate_requests') || '[]');

// Qualifying warehouse renovation estimate for Chicago, IL
const qualifyingEstimates = estimates.filter(e => (
  e.project_type === 'warehouse_renovation' &&
  e.location_city && e.location_city.toLowerCase() === 'chicago' &&
  e.location_state === 'IL' &&
  Number(e.floor_area_sq_ft || 0) === 10000 &&
  e.hvac_efficiency_level === 'high_efficiency' &&
  Number(e.target_energy_savings_percent || 0) >= 15
));

// CP1 (0.40): User generated at least one qualifying cost estimate
checkpoints.push({
  passed: qualifyingEstimates.length > 0,
  weight: 0.4
});

// CP2 (0.60): User submitted an estimate request for one of these, as a warehouse/industrial facility via email/quote form
const qualifyingEstimateIds = qualifyingEstimates.map(e => e.id);
const validSubmittedVia = ['email_this_estimate', 'request_detailed_quote'];

const qualifyingRequests = requests.filter(r => (
  qualifyingEstimateIds.includes(r.costEstimateId) &&
  r.facility_type === 'warehouse_industrial' &&
  validSubmittedVia.includes(r.submitted_via)
));

checkpoints.push({
  passed: qualifyingRequests.length > 0,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const inquiries = JSON.parse(localStorage.getItem('inquiries') || '[]');
const budgetOptions = JSON.parse(localStorage.getItem('budget_range_options') || '[]');

// Budget option representing $500,000–$800,000 for design-build contact
const matchingBudgetOptions = budgetOptions.filter(b => (
  b.applies_to === 'contact_design_build' &&
  Number(b.min_amount) === 500000 &&
  Number(b.max_amount) === 800000
));
const matchingBudgetOptionIds = matchingBudgetOptions.map(b => b.id);

function isOctober2026(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d)) return false;
  return d.getUTCFullYear() === 2026 && d.getUTCMonth() === 9; // October = 9
}

// Inquiries that match all specified criteria
const qualifyingInquiries = inquiries.filter(q => {
  if (q.inquiry_type !== 'design_build_project') return false;
  if (q.project_type !== 'retail_store') return false;
  const size = Number(q.project_size_sq_ft || 0);
  if (!(size >= 7000 && size <= 9000)) return false; // approx 8,000 sq ft
  // Budget range via option or explicit amounts
  const viaOption = q.budgetRangeOptionId && matchingBudgetOptionIds.includes(q.budgetRangeOptionId);
  const viaAmounts = Number(q.budget_min_amount || 0) === 500000 && Number(q.budget_max_amount || 0) === 800000;
  if (!viaOption && !viaAmounts) return false;
  if (!isOctober2026(q.desired_start_date)) return false;
  if (q.referral_source !== 'online_search') return false;
  if (q.preferred_contact_method !== 'phone') return false;
  if (q.preferred_contact_time_window !== 'afternoon_2_4') return false;
  return true;
});

// Single checkpoint (1.0): A design-build retail inquiry matches all task requirements
checkpoints.push({
  passed: qualifyingInquiries.length > 0,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
